INSERT INTO weekly_reports (project_id, week_number, week_start, week_end, available_at, data) VALUES ('fc1eb067-a7d9-41e1-bd39-1845e750c3b7', 1, '2026-01-19', '2026-01-25', now(), '{"kpis": {"physicalPlanned": 5, "physicalActual": 6, "scheduleVarianceDays": 0, "costVariance": 0}, "executiveSummary": "A primeira semana de atividades da reforma do Apartamento Modelo Brooklin transcorreu conforme o planejado, com a atividade de compatibilização técnica inicial concluída. Houve um progresso físico real ligeiramente superior ao planejado, atingindo 6% contra os 5% previstos.", "highlights": ["Conclusão da compatibilização técnica inicial entre todas as disciplinas.", "Definição das diretrizes para instalações hidráulicas e elétricas.", "Abertura de todas as frentes de trabalho."], "risks": [], "nextWeekFocus": ["Mobilização completa do canteiro.", "Início do detalhamento executivo.", "Contratação dos principais fornecedores."], "weatherImpact": "Sem impacto", "safetyNotes": "Reunião de integração de segurança realizada com a equipe.", "activities": [{"activityId": "a1", "description": "Compatibilização técnica inicial entre disciplinas e definição dos parâmetros executivos da obra.", "plannedStart": "2026-01-19", "plannedEnd": "2026-01-23", "actualStart": "2026-01-19", "actualEnd": "2026-01-23", "weight": 5, "percentComplete": 100, "status": "concluído", "varianceDays": 0}], "gallery": [{"id": "g1", "url": "https://images.unsplash.com/photo-1581094794329-c8112a89af12?w=1200&q=80", "caption": "Reunião de compatibilização técnica", "area": "Geral", "category": "Planejamento", "date": "2026-01-19"}, {"id": "g2", "url": "https://images.unsplash.com/photo-1503387762-592deb58ef4e?w=1200&q=80", "caption": "Plantas e projetos no local", "area": "Escritório", "category": "Planejamento", "date": "2026-01-21"}, {"id": "g3", "url": "https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?w=1200&q=80", "caption": "Análise de projetos executivos", "area": "Geral", "category": "Planejamento", "date": "2026-01-23"}], "incidents": [], "weekNumber": 1, "periodStart": "2026-01-19", "periodEnd": "2026-01-25", "issuedAt": "2026-01-25", "unitName": "Apto Demo Brooklin", "projectId": "fc1eb067-a7d9-41e1-bd39-1845e750c3b7"}'::jsonb) ON CONFLICT (project_id, week_number) DO UPDATE SET week_start = EXCLUDED.week_start, week_end = EXCLUDED.week_end, available_at = EXCLUDED.available_at, data = EXCLUDED.data, updated_at = now();
INSERT INTO weekly_reports (project_id, week_number, week_start, week_end, available_at, data) VALUES ('fc1eb067-a7d9-41e1-bd39-1845e750c3b7', 2, '2026-01-26', '2026-02-01', now(), '{"kpis": {"physicalPlanned": 10, "physicalActual": 9, "scheduleVarianceDays": 0, "costVariance": 0}, "executiveSummary": "A Semana 2 focou na execução de ajustes nas instalações elétricas. Progresso real ficou ligeiramente abaixo do planejado (9% vs 10%). Não conformidade em pontos de iluminação foi identificada e será endereçada.", "highlights": ["Finalização de 80% dos ajustes finos na infraestrutura elétrica.", "Instalação e testes preliminares de quadros de distribuição.", "Melhora na organização do canteiro."], "risks": [{"title": "Não conformidade em pontos de iluminação.", "severity": "medium", "mitigation": "Revisão e correção dos pontos em desacordo com o projeto elétrico."}], "nextWeekFocus": ["Correção dos pontos de iluminação.", "Início da preparação de superfícies para pintura."], "weatherImpact": "Sem impacto", "safetyNotes": "Todos os trabalhadores utilizaram EPIs adequados.", "activities": [{"activityId": "a2", "description": "Execução de ajustes em instalações elétricas", "plannedStart": "2026-01-26", "plannedEnd": "2026-01-30", "actualStart": "2026-01-26", "actualEnd": "2026-01-30", "weight": 5, "percentComplete": 100, "status": "concluído", "varianceDays": 0}], "gallery": [{"id": "g1", "url": "https://images.unsplash.com/photo-1581092334651-ddf26d9a09d0?w=1200&q=80", "caption": "Passagem de eletrodutos", "area": "Geral", "category": "Elétrica", "date": "2026-01-26"}, {"id": "g2", "url": "https://images.unsplash.com/photo-1565608087341-404b25492fee?w=1200&q=80", "caption": "Instalações elétricas em execução", "area": "Sala", "category": "Elétrica", "date": "2026-01-28"}, {"id": "g3", "url": "https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1200&q=80", "caption": "Quadro de distribuição em montagem", "area": "Hall", "category": "Elétrica", "date": "2026-01-30"}], "incidents": [], "weekNumber": 2, "periodStart": "2026-01-26", "periodEnd": "2026-02-01", "issuedAt": "2026-02-01", "unitName": "Apto Demo Brooklin", "projectId": "fc1eb067-a7d9-41e1-bd39-1845e750c3b7"}'::jsonb) ON CONFLICT (project_id, week_number) DO UPDATE SET week_start = EXCLUDED.week_start, week_end = EXCLUDED.week_end, available_at = EXCLUDED.available_at, data = EXCLUDED.data, updated_at = now();
INSERT INTO weekly_reports (project_id, week_number, week_start, week_end, available_at, data) VALUES ('fc1eb067-a7d9-41e1-bd39-1845e750c3b7', 3, '2026-02-02', '2026-02-08', now(), '{"kpis": {"physicalPlanned": 17, "physicalActual": 18, "scheduleVarianceDays": 0, "costVariance": 0}, "executiveSummary": "Semana 3 marcada pela conclusão das instalações elétricas conforme cronograma. Progresso físico real superou ligeiramente o planejado.", "highlights": ["Conclusão de 100% das instalações elétricas da etapa.", "Atingimento de 18% de progresso físico acumulado.", "Boa coordenação entre frentes de trabalho."], "risks": [], "nextWeekFocus": ["Início das instalações hidráulicas.", "Fechamento de paredes conforme projeto.", "Recebimento de materiais."], "weatherImpact": "Sem impacto", "safetyNotes": "Nenhum incidente registrado. Treinamento reforçado.", "activities": [{"activityId": "a3", "description": "Instalações elétricas", "plannedStart": "2026-02-02", "plannedEnd": "2026-02-06", "actualStart": "2026-02-02", "actualEnd": "2026-02-06", "weight": 7, "percentComplete": 100, "status": "concluído", "varianceDays": 0}], "gallery": [{"id": "g1", "url": "https://images.unsplash.com/photo-1621905251189-08b45d6a269e?w=1200&q=80", "caption": "Pontos elétricos finalizados", "area": "Cozinha", "category": "Elétrica", "date": "2026-02-02"}, {"id": "g2", "url": "https://images.unsplash.com/photo-1565608087341-404b25492fee?w=1200&q=80", "caption": "Instalações elétricas concluídas", "area": "Sala", "category": "Elétrica", "date": "2026-02-04"}, {"id": "g3", "url": "https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1200&q=80", "caption": "Quadro elétrico energizado", "area": "Hall", "category": "Elétrica", "date": "2026-02-06"}], "incidents": [], "weekNumber": 3, "periodStart": "2026-02-02", "periodEnd": "2026-02-08", "issuedAt": "2026-02-08", "unitName": "Apto Demo Brooklin", "projectId": "fc1eb067-a7d9-41e1-bd39-1845e750c3b7"}'::jsonb) ON CONFLICT (project_id, week_number)